protected override bool ShouldRetryOn(Exception exception)
    {
        if (_additionalErrorNumbers != null
            && exception is SqlException sqlException)
        {
            foreach (SqlError err in sqlException.Errors)
            {
                if (_additionalErrorNumbers.Contains(err.Number))
                {
                    return true;
                }
            }
        }

        return SqlServerTransientExceptionDetector.ShouldRetryOn(exception);
    }

public override bool IsValid(ValidationContext<T> context, TProperty value) {
	var comparisonValue = GetComparisonValue(context);
	bool success = Compare(comparisonValue, value);

	if (!success) {
		context.MessageFormatter.AppendArgument("ComparisonValue", comparisonValue);
		context.MessageFormatter.AppendArgument("ComparisonProperty", _memberDisplayName ?? "");

		return false;
	}

	return true;
}

public override bool IsValid(ValidationContext<T> context, TProperty value) {
	// If the value is null then we abort and assume success.
	// This should not be a failure condition - only a NotNull/NotEmpty should cause a null to fail.
	if (value == null) return true;

	if (HasError(value)) {

		context.MessageFormatter
			.AppendArgument("From", From)
			.AppendArgument("To", To);

		return false;
	}
	return true;
}

public string GetErrorMessage(ValidationContext<T> context, TProperty value) {
	// Use a custom message if one has been specified.
	string rawTemplate = _errorMessageFactory?.Invoke(context, value) ?? _errorMessage;


	// If no custom message has been supplied, use the default.
	if (rawTemplate == null) {
		rawTemplate = Validator.GetDefaultMessageTemplate(ErrorCode);
	}

	if (context == null) {
		return rawTemplate;
	}

	return context.MessageFormatter.BuildMessage(rawTemplate);
}

public virtual ValidationResult Validate(ValidationContext<T> context) {
	ArgumentNullException.ThrowIfNull(context);

	try {
		return ValidateInternal(context);
	}
	catch (AsyncValidatorInvokedSynchronouslyException) {
		// If we attempted to execute an async validator, re-create the exception with more useful info.
		bool wasInvokedByMvc = context.RootContextData.ContainsKey("InvokedByMvc");
		throw new AsyncValidatorInvokedSynchronouslyException(GetType(), wasInvokedByMvc);
	}
}

public override IValidator GetValidator(ValidationContext<T> context, TProperty value) {
	// bail out if the current item is null
	if (value == null) return null;

	if (_derivedValidators.TryGetValue(value.GetType(), out var derivedValidatorFactory)) {
		return derivedValidatorFactory.GetValidator(context, value);
	}

	return null;
}

public virtual RateLimitHeaders GetHeaders(HttpContext context, RateLimitOptions options, DateTime now, RateLimitCounter counter)
    {
        var rule = options.Rule;
        return new RateLimitHeaders(context,
            limit: rule.Limit,
            remaining: rule.Limit - counter.Total,
            reset: counter.StartedAt + rule.PeriodSpan);
    }

protected virtual Task Break(HttpContext context, RateLimitOptions options, double retryAfter)
    {
        var retryAfterHeader = retryAfter.ToString(CultureInfo.InvariantCulture);
        var ds = ReturnQuotaExceededResponse(context, options, retryAfterHeader);
        context.Items.UpsertDownstreamResponse(ds);
        var error = new QuotaExceededError(GetResponseMessage(options), options.StatusCode);
        context.Items.SetError(error);
        return Task.CompletedTask;
    }

protected virtual ClientRequestIdentity Identify(HttpContext context, RateLimitOptions options, DownstreamRoute route)
    {
        var clientId = string.Empty;
        var header = options.ClientIdHeader.IfEmpty(RateLimitOptions.DefaultClientHeader);
        if (context.Request.Headers.TryGetValue(header, out var headerValue))
        {
            clientId = headerValue;
        }

        return new ClientRequestIdentity(clientId, route.LoadBalancerKey);
    }

private static DownstreamResponse CreateHttpResponseMessage(CachedResponse cached)
    {
        var content = new MemoryStream(Convert.FromBase64String(cached.Body));
        var streamContent = new StreamContent(content);
        foreach (var header in cached.ContentHeaders)
        {
            streamContent.Headers.TryAddWithoutValidation(header.Key, header.Value);
        }

        return new DownstreamResponse(streamContent, cached.StatusCode, cached.Headers.ToList(), cached.ReasonPhrase);
    }

public virtual HttpMessageInvoker Get(DownstreamRoute downstreamRoute)
    {
        // Since the comparison is based on the downstream route object reference,
        // and the QoS Options properties can't be changed after the route is created,
        // we don't need to use the timeout value as part of the cache key.
        return _handlersPool.GetOrAdd(
            new MessageInvokerCacheKey(downstreamRoute),
            cacheKey => new Lazy<HttpMessageInvoker>(() => CreateMessageInvoker(cacheKey.Route))
        ).Value;
    }

public override async Task SetParametersAsync(ParameterView parameters)
